namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string DepartmentCode { get; set; } = string.Empty;
    public string CourseNumber { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }

    public string FullCode => $"{DepartmentCode} {CourseNumber}";
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language arts." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and their impact on civilization." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published extensively on CS education.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming).", Credits = 4, Schedule = "TTh 10:30–11:45 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm design and competitive programming. He has coached multiple ICPC teams.", IsFeatured = true },
            new() { Id = 3, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "350", Title = "Operating Systems", Description = "Covers process management, memory management, file systems, and concurrency. Includes hands-on kernel programming projects.", Credits = 4, Schedule = "MWF 1:00–1:50 PM", InstructorName = "Dr. Maria Rodriguez", InstructorBio = "Dr. Rodriguez contributed to the Linux kernel and brings real-world systems experience to the classroom." },
            new() { Id = 4, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics.", Credits = 4, Schedule = "MWF 8:00–8:50 AM", InstructorName = "Dr. Robert Klein", InstructorBio = "Dr. Klein is an award-winning educator who has developed innovative approaches to teaching calculus." },
            new() { Id = 5, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to data science.", Credits = 3, Schedule = "TTh 1:00–2:15 PM", InstructorName = "Dr. Emily Watson", InstructorBio = "Dr. Watson researches applications of linear algebra in machine learning and signal processing.", IsFeatured = true },
            new() { Id = 6, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Laboratory component included. Calculus-based approach.", Credits = 4, Schedule = "MWF 10:00–10:50 AM, Lab: F 2:00–4:50 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is a former NASA researcher with expertise in experimental physics." },
            new() { Id = 7, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "220", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "TTh 9:00–10:15 AM", InstructorName = "Dr. Lisa Huang", InstructorBio = "Dr. Huang's research focuses on photonics and she holds several patents in optical communications." },
            new() { Id = 8, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "110", Title = "College Composition", Description = "Develop essential academic writing skills. Focus on argumentation, research methods, and clear prose.", Credits = 3, Schedule = "MWF 11:00–11:50 AM", InstructorName = "Prof. David Miller", InstructorBio = "Prof. Miller is a published author and writing coach with 20 years of teaching experience.", IsFeatured = true },
            new() { Id = 9, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present, exploring themes of identity and culture.", Credits = 3, Schedule = "TTh 2:30–3:45 PM", InstructorName = "Dr. Angela Brooks", InstructorBio = "Dr. Brooks specializes in 20th-century American fiction and has authored two books on the Harlem Renaissance." },
            new() { Id = 10, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "101", Title = "World Civilizations", Description = "Survey of major world civilizations from antiquity to 1500 CE. Examines political, social, and cultural developments.", Credits = 3, Schedule = "MWF 2:00–2:50 PM", InstructorName = "Dr. Thomas Grant", InstructorBio = "Dr. Grant has conducted archaeological research in the Mediterranean and brings artifacts into the classroom." },
            new() { Id = 11, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "301", Title = "Modern European History", Description = "Europe from the French Revolution to the present. Topics include industrialization, nationalism, world wars, and the EU.", Credits = 3, Schedule = "TTh 11:00 AM–12:15 PM", InstructorName = "Dr. Catherine Novak", InstructorBio = "Dr. Novak is a specialist in Central European history and serves as editor of the Journal of Modern European Studies.", IsFeatured = true },
        };
    }

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public IReadOnlyList<Course> GetAllCourses() => _courses;

    public IReadOnlyList<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public IReadOnlyList<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.FullCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && GetCourse(request.CourseId) is not null;
    }
}

